import { useMemo } from "react";
export function useDropAccept(props, gridId) {
    const dropAccept = useMemo(() => {
        const drop = props.rowDropAccept ?? [];
        if (!drop.includes(gridId))
            drop.push(gridId);
        return drop.map((x) => `grid:${x}`);
    }, [gridId, props.rowDropAccept]);
    return dropAccept;
}
